import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Balance {
  totalBudget: number;
  spent: number;
  remaining: number;
}

interface SpendingCategory {
  name: string;
  value: number;
}

interface BudgetData {
  balance: Balance;
  spendingCategories: SpendingCategory[];
}

export default function Widget() {
  const budgetData = response.data as BudgetData;
  const { balance, spendingCategories } = budgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              Budget Overview
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Total Budget: ${balance.totalBudget.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Spent: ${balance.spent.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Remaining: ${balance.remaining.toLocaleString()}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Spending Categories
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {spendingCategories.map((category, index) => (
                <Chip
                  key={index}
                  label={`${category.name}: $${category.value}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <PieChart
            height={150}
            series={[
              {
                data: spendingCategories.map((category) => ({
                  value: category.value,
                  label: category.name,
                })),
                color: '#FF5722',
              },
            ]}
            sx={{ '& .MuiPieElement-root': { stroke: '#FFFFFF', strokeWidth: 1 } }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
